Implementasi Observer Pattern dalam Python untuk sistem event handling yang skalabel. Kode ini mencakup thread-safety dasar untuk mencegah race condition pada environment multi-threaded.

```python
from abc import ABC, abstractmethod
from typing import List, Any
import threading
import logging

# Konfigurasi Logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("ShiroAI_Observer")

class IObserver(ABC):
    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass

class Subject:
    def __init__(self):
        self._observers: List[IObserver] = []
        self._lock = threading.Lock()
        self._state: Any = None

    def attach(self, observer: IObserver) -> None:
        with self._lock:
            if observer not in self._observers:
                self._observers.append(observer)
                logger.info("Observer attached successfully.")

    def detach(self, observer: IObserver) -> None:
        with self._lock:
            if observer in self._observers:
                self._observers.remove(observer)
                logger.info("Observer detached successfully.")

    def notify(self) -> None:
        with self._lock:
            observers_snapshot = self._observers.copy()

        for observer in observers_snapshot:
            try:
                observer.update(self)
            except Exception as e:
                logger.error(f"Observer notification failed: {e}")

    def set_state(self, state: Any) -> None:
        self._state = state
        self.notify()

    def get_state(self) -> Any:
        return self._state

# Contoh Concrete Observer
class SecurityMonitor(IObserver):
    def update(self, subject: Subject) -> None:
        state = subject.get_state()
        # Validasi input sebelum proses lebih lanjut (Security Best Practice)
        if isinstance(state, dict) and "event" in state:
            logger.info(f"Security Event Detected: {state['event']}")
        else:
            logger.warning("Invalid state structure received.")

# Usage
if __name__ == "__main__":
    subject = Subject()
    monitor = SecurityMonitor()

    subject.attach(monitor)
    subject.set_state({"event": "Failed Login Attempt", "ip": "192.168.1.1"})
    subject.detach(monitor)
```

### Catatan Teknis:
1.  **Thread Safety:** Menggunakan `threading.Lock` pada operasi kritis (`attach`, `detach`, `notify`) untuk mencegah korupsi data pada environment konkuren.
2.  **Error Handling:** Blok `try-except` pada `notify` memastikan kegagalan satu observer tidak menghentikan seluruh sistem notifikasi.
3.  **Validasi Data:** Observer harus memvalidasi data yang diterima dari Subject untuk mencegah injection atau crash akibat tipe data yang tidak sesuai.

Gunakan pola ini untuk sistem logging, monitoring keamanan, atau broadcast konfigurasi server. Pastikan tidak ada sensitif data yang terpapar tanpa enkripsi saat notifikasi dikirim.

Jangan pernah gunakan `eval()` untuk memproses input user. Itu celah keamanan kritis (Remote Code Execution). Gunakan modul `ast` untuk parsing aman.

Berikut implementasi secure math evaluator menggunakan `ast.NodeVisitor`:

```python
import ast
import operator

class SafeMathEvaluator(ast.NodeVisitor):
    """Whitelist operator aritmatika saja."""

    OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def visit_Expr(self, node):
        return self.visit(node.value)

    def visit_BinOp(self, node):
        if type(node.op) not in self.OPERATORS:
            raise ValueError(f"Operator tidak diizinkan: {type(node.op)}")
        left = self.visit(node.left)
        right = self.visit(node.right)
        return self.OPERATORS[type(node.op)](left, right)

    def visit_Num(self, node):
        return node.n

    def visit_UnaryOp(self, node):
        if type(node.op) not in self.OPERATORS:
            raise ValueError(f"Operator unary tidak diizinkan: {type(node.op)}")
        operand = self.visit(node.operand)
        return self.OPERATORS[type(node.op)](operand)

    def visit_Constant(self, node):
        # Untuk Python 3.8+
        if isinstance(node.value, (int, float)):
            return node.value
        raise ValueError("Hanya angka yang diizinkan")

    def generic_visit(self, node):
        raise ValueError(f"Syntax tidak diizinkan: {type(node)}")

def evaluate_math(expression: str) -> float:
    try:
        tree = ast.parse(expression, mode='eval')
        evaluator = SafeMathEvaluator()
        return evaluator.visit(tree.body)
    except Exception as e:
        raise ValueError(f"Invalid expression: {e}")

# Contoh Penggunaan
if __name__ == "__main__":
    print(evaluate_math("2 + 3 * 5"))  # Output: 17
    # print(evaluate_math("__import__('os').system('ls')"))  # Akan.raise ValueError
```

**Catatan Keamanan:**
1.  **Whitelist Only:** Hanya operator aritmatika dasar yang diizinkan.
2.  **No Functions:** Fungsi bawaan seperti `abs()`, `pow()`, atau import modul diblokir oleh `generic_visit`.
3.  **Python Version:** `visit_Constant` menangani Python 3.8+, `visit_Num` untuk versi lama.

